/**
 * @file UserResolvers.ts
 * @description Defines resolver functions for user-related GraphQL queries and mutations.
 */

import { User } from '../../database/models/User';
import { comparePasswords, hashPassword } from '../../utils/passport';

/**
 * @interface UserSignup
 * @description Represents the shape of user signup input data.
 */
interface UserSignup {
	firstName: string;
	email: string;
	password: string;
}

/**
 * @interface UserLogout
 * @description Represents the shape of user logout input data.
 */
interface UserLogout {
	email: string;
}

/**
 * @interface UserDeleteAccount
 * @description Represents the shape of user delete account input data.
 */
interface UserDeleteAccount {
	email: string;
	password: string;
}

/**
 * @interface IncrementEntries
 * @description Represents the shape of input data for incrementing user entries.
 */
interface IncrementEntries {
	email: string;
}

/**
 * @namespace UserQueries
 * @description Contains resolver functions for user-related GraphQL queries.
 */
export const UserQueries = {

	/**
	 * @async
	 * @function getCurrentUser
	 * @description Retrieves the currently authenticated user.
	 * @param {unknown} _parent - Parent resolver object.
	 * @param {unknown} _args - Resolver arguments.
	 * @param {any} context - Context object containing authentication information.
	 * @returns {Promise&lt;any&gt;} The currently authenticated user.
	 */
	 async getCurrentUser(_parent: unknown, _args: unknown, context: any): Promise&lt;any&gt; {
		 return await context.getUser();
	},
};

/**
 * @namespace UserMutations
 * @description Contains resolver functions for user-related GraphQL mutations.
 */
export const UserMutations = {

	/**
	 * @async
	 * @function signup
	 * @description Registers a new user account.
	 * @param {unknown} _parent - Parent resolver object.
	 * @param {UserSignup} args - User signup input data.
	 * @returns {Promise&lt;any&gt;} The newly created user object.
	 */
	async signup(_parent: unknown, args: UserSignup): Promise&lt;any&gt; {
		const { firstName, email, password } = args;
		const lowerCaseEmail = email.toLowerCase();

		if (password.length &lt; 8) {
			throw new Error('Password length must be at least 8 characters');
		}

		if (!lowerCaseEmail.includes('@')) {
			throw new Error('Email has an invalid format.');
		}

		const oldUser = await User.findOne({ email: lowerCaseEmail });
		if (oldUser) {
			throw new Error('An account with this email already exists.');
		}

		const hashedPassword = await hashPassword(password);

		const newUser = new User({
			firstName: firstName,
			email: lowerCaseEmail,
			password: hashedPassword,
			entries: 0,
			dateJoined: Date.now(),
			isActive: true,
			isLoggedIn: true,
		});

		return await newUser.save();
	},

	/**
	 * @async
	 * @function login
	 * @description Authenticates a user and logs them in.
	 * @param {any} _parent - Parent resolver object.
	 * @param {any} args - User login input data.
	 * @param {any} context - Context object containing authentication utilities.
	 * @returns {Promise&lt;any&gt;} The authenticated user object.
	 */
	async login(_parent: any, { email, password }: any, context: any): Promise&lt;any&gt; {
		const lowerCaseEmail = email.toLowerCase();
		const { user } = await context.authenticate('graphql-local', {
			email: lowerCaseEmail,
			password,
		});

		const isValidPassword = await comparePasswords(password, user.password);

		if (!isValidPassword || !lowerCaseEmail) {
			throw new Error('Incorrect Credentials');
		}

		if (!user.isActive) {
			throw new Error('Account is not active.');
		}

		user.isLoggedIn = true;
		const savedUser = await user.save(); // Save the user first
		await context.login(savedUser); // Call login with the saved user

		return savedUser;
	},

	/**
	 * @async
	 * @function logout
	 * @description Logs out a user.
	 * @param {unknown} _parent - Parent resolver object.
	 * @param {UserLogout} args - User logout input data.
	 * @returns {Promise&lt;any&gt;} The updated user object after logout.
	 */
	async logout(_parent: unknown, args: UserLogout): Promise&lt;any&gt; {
		const { email } = args;
		const lowerCaseEmail = email.toLowerCase();
		const user = await User.findOne({
			email: lowerCaseEmail,
		});

		if (!user) {
			throw new Error('User not found');
		}

		user.isLoggedIn = false;
		return await user.save();
	},

	/**
	 * @async
	 * @function deleteUserAccount
	 * @description Deletes a user account.
	 * @param {unknown} _parent - Parent resolver object.
	 * @param {UserDeleteAccount} args - User delete account input data.
	 * @returns {Promise&lt;any&gt;} The deleted user object.
	 */
	async deleteUserAccount(_parent: unknown, args: UserDeleteAccount): Promise&lt;any&gt; {
		const { email } = args;
		const lowerCaseEmail = email.toLowerCase();

		const user = await User.findOne({
			email: lowerCaseEmail,
		});

		if (!user) {
			throw new Error('User does not exist');
		}

		const deletedUser = User.findOneAndDelete({
			email: lowerCaseEmail,
		});

		if (!deletedUser) {
			throw new Error('Failed to delete user');
		}

		return deletedUser;
	},

	/**
	 * @async
	 * @function incrementUserEntries
	 * @description Increments the entry count for a user.
	 * @param {any} _parent - Parent resolver object.
	 * @param {IncrementEntries} args - Input data for incrementing user entries.
	 * @returns {Promise&lt;any&gt;} The updated user object with incremented entries.
	 */
	async incrementUserEntries(_parent: any, args: IncrementEntries): Promise&lt;any&gt; {

		const { email } = args;
		const lowerCaseEmail = email.toLowerCase();

		const currentUser = await User.findOne({
			email: lowerCaseEmail,
		});

		if (!currentUser) {
			throw new Error('User not found');
		}

		currentUser.entries += 1;
		await currentUser.save();

		return currentUser;
	},
};

And some frontend code:
/**
 * @file UserContext.tsx
 * @description Provides a context for managing user data.
 */

import React, {
	createContext,
	ReactNode,
	useContext, useMemo,
} from 'react';

import { useQuery } from '@apollo/client';

import { GET_CURRENT_USER } from '@/graphql/queries/GetCurrentUser';
import { UserInterface } from '../../backend/database/models/User';
import CircularProgress from '@mui/material/CircularProgress';
import { client } from '@/config/apolloClient';

// Define the context for user data
const UserContext = createContext&lt;Partial&lt;UserInterface&gt;&gt;({});

/**
 * @function useUser
 * @description Custom hook to consume the user context.
 * @returns {Partial&lt;UserInterface&gt;} The user context.
 */
export const useUser = (): Partial&lt;UserInterface&gt; =&gt; {
	return useContext(UserContext);
};


/**
 * @interface UserProviderProps
 * @description Represents the props for the UserContext component.
 * @property {ReactNode} children The children within the UserContext component to be rendered.
 */
interface UserProviderProps {
	children: ReactNode;
}

/**
 * @function UserProvider
 * @description Provides the user context to its children.
 * @param {UserProviderProps} props - The props for the UserProvider component.
 * @returns {React.ReactElement} A UserProvider component.
 */
export const UserProvider: React.FC&lt;UserProviderProps&gt; = ({ children }: UserProviderProps): React.ReactElement =&gt; {
	const { loading, error, data } = useQuery(GET_CURRENT_USER);
	console.log('Current User in User Provider', data);

	// Handle error in fetching user data
	if (error) {
		return (
			&lt;div className=&quot;flex justify-center items-center h-screen bg-red-100&quot;&gt;
				&lt;div className=&quot;p-4 rounded-md bg-red-500 text-white&quot;&gt;
					&lt;p&gt;Error: {error.message}&lt;/p&gt;
				&lt;/div&gt;
			&lt;/div&gt;
		);
	}

	// Memoize the current user object to prevent unnecessary re-renders
	const currentUser = useMemo(() =&gt; {
		return data ? { ...data.getCurrentUser } : {};
	}, [data]);

	console.log('Current User memo', currentUser);

	// Render loading indicator while fetching user data
	return (
		&lt;UserContext.Provider value={currentUser}&gt;
			{loading ? (
				&lt;div className={'flex justify-center items-center h-screen'}&gt;
					&lt;CircularProgress sx={{
						color: 'rgb(164, 110, 231)',
					}} /&gt;
				&lt;/div&gt;
			) : (
				children
			)}
		&lt;/UserContext.Provider&gt;
	);
};

/**
 * @file AuthGuard.tsx
 * @description Defines a component for guarding routes based on user authentication status.
 */

import React from 'react';
import { useRouter, NextRouter } from 'next/router';

import { useQuery } from '@apollo/client';

import { useUser } from '@/contexts/UserContext';
import { GET_CURRENT_USER } from '@/graphql/queries/GetCurrentUser';

/**
 * @function AuthGuard
 * @description A component that guards routes based on user authentication status.
 * @param children - The child components to be rendered if the user is authenticated.
 * @returns The child components if the user is authenticated, otherwise redirects to the login page.
 */
export const AuthGuard: React.FC&lt;{ children: React.ReactNode }&gt; = ({ children }) =&gt; {
	const { data, loading } = useQuery(GET_CURRENT_USER);
	const user = useUser() || {};
	console.log(&quot;User in AuthGuard&quot;, data);
	console.log(&quot;User in AuthGuard userHook&quot;, user);
	const { isLoggedIn, email, isActive } = user;
	const router: NextRouter = useRouter();

	if (loading) {
		// Display a loading indicator or a fallback component while data is being fetched
		return &lt;div&gt;Loading Auth guard...&lt;/div&gt;;
	}

	if (!data || !data.getCurrentUser || !isLoggedIn || !email || !isActive) {
		// Redirect to the login page if user data is not available or user is not authenticated
		router.push('/login').catch((error) =&gt; {
			console.error('Error during navigation:', error);
		});
		return null;
	}

	return &lt;&gt;{children}&lt;/&gt;;
};

Sure, here is an example of how you could implement Redis and refresh tokens to improve session handling when deployed to Heroku:

**Backend**

1. Install connect-redis and redis packages:

```
npm install connect-redis redis
```

2. Configure Redis store and connect to Redis URL:

```js
const RedisStore = require('connect-redis')(session);

const redisClient = redis.createClient({
  url: `redis://${process.env.REDIS_URL}`  
});

app.use(session({
  store: new RedisStore({client: redisClient}),
  //...
}))
```

3. Generate a refresh token on user login: 

```js
// Login mutation

const refreshToken = jwt.sign({userId: user._id}, process.env.REFRESH_TOKEN_SECRET); 

// Save refreshToken to database
await User.findByIdAndUpdate(user._id, {refreshToken});

// Return refreshToken with main JWT token
return {
  token: jwtToken,
  refreshToken 
}
```

4. Handle refreshing tokens when JWT expires:

```js
// Refresh token mutation

const {refreshToken} = req.body;

if (!refreshToken) {
  throw new Error('No refresh token');
}

const user = await User.findOne({refreshToken});

if (!user) {
  throw new Error('Invalid refresh token');
} 

// Generate new JWT
const newJWT = jwt.sign({userId: user._id}, process.env.JWT_SECRET, {expiresIn: '1h'});

// Clear old refresh token
await User.findByIdAndUpdate(user._id, {refreshToken: ''}); 

// Generate new refresh token
const newRefreshToken = jwt.sign({userId: user._id}, process.env.REFRESH_TOKEN_SECRET);

// Save new refresh token and return new JWT
await User.findByIdAndUpdate(user._id, {refreshToken: newRefreshToken});

return {
  token: newJWT,
  refreshToken: newRefreshToken
}
```

**Frontend**

5. Handle null user by logging out:

```js
// UserContext.js

if (!data || !data.getCurrentUser) {
  logoutUser(); // Log user out
  router.push('/login')
}

const logoutUser = () => {
  // Clear user data and tokens 
}
```

6. Call refresh token mutation when JWT expires:

```js
// authService.js

const refreshAccessToken = async () => {
  const response = await axios.post('/refresh-token', {
    refreshToken: getRefreshToken() 
  });

  // Update tokens 
  setAccessToken(response.data.token);
  setRefreshToken(response.data.refreshToken);
}

axios.interceptors.response.use(
  (response) => response,
  async (error) => {
    const status = error?.response?.status;

    if (status === 401) {
      // Try to refresh token
      await refreshAccessToken();

      // Retry request
      return axios(error.config); 
    }

    return Promise.reject(error);
  }
)
```

